
'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Loader2, User, Mail, Phone } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { getParents, type ParentWithChildren } from '@/services/parents';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';

export default function ParentManagementPage() {
  const [parents, setParents] = useState<ParentWithChildren[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedParent, setSelectedParent] = useState<ParentWithChildren | null>(null);
  const [isDetailsOpen, setIsDetailsOpen] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      try {
        const fetchedParents = await getParents();
        setParents(fetchedParents);
      } catch (error) {
        console.error("Failed to fetch parents:", error);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, []);

  const handleViewDetails = (parent: ParentWithChildren) => {
    setSelectedParent(parent);
    setIsDetailsOpen(true);
  }

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold font-headline">Parent Management</h1>
        <p className="text-muted-foreground">View and manage parent and guardian information.</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Parent Directory</CardTitle>
          <CardDescription>A list of all parents and their children in the system.</CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex justify-center items-center py-10">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Parent/Guardian</TableHead>
                    <TableHead className="hidden md:table-cell">Contact</TableHead>
                    <TableHead>Children</TableHead>
                    <TableHead><span className="sr-only">Actions</span></TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {parents.map((parent) => (
                    <TableRow key={parent.email}>
                      <TableCell className="font-medium">
                        <div className="flex items-center gap-3">
                          <Avatar>
                            <AvatarImage src={`https://placehold.co/40x40.png`} alt={parent.name} data-ai-hint="person avatar" />
                            <AvatarFallback>{parent.name.split(' ').map(n => n[0]).join('')}</AvatarFallback>
                          </Avatar>
                          <div className="flex flex-col">
                             <span>{parent.name}</span>
                             <span className="text-muted-foreground text-sm md:hidden">{parent.email}</span>
                          </div>
                        </div>
                      </TableCell>
                      <TableCell className="hidden md:table-cell">
                        <div className="flex flex-col">
                            <span>{parent.email}</span>
                            <span className="text-muted-foreground">{parent.phone}</span>
                        </div>
                      </TableCell>
                      <TableCell>
                        {parent.children.map(child => child.name).join(', ')}
                      </TableCell>
                      <TableCell>
                        <Button variant="outline" size="sm" onClick={() => handleViewDetails(parent)}>
                            View Details
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>
      
       {/* View Parent Details Dialog */}
      <Dialog open={isDetailsOpen} onOpenChange={setIsDetailsOpen}>
          <DialogContent>
              <DialogHeader>
                  <DialogTitle>Parent/Guardian Details</DialogTitle>
                  <DialogDescription>Contact information for {selectedParent?.name}.</DialogDescription>
              </DialogHeader>
              {selectedParent && (
                  <div className="grid gap-4 py-4 text-sm">
                      <div className="flex items-center gap-4">
                          <User className="h-5 w-5 text-muted-foreground" />
                          <div className="flex flex-col">
                            <span className="text-muted-foreground">Name</span>
                            <span>{selectedParent.name}</span>
                          </div>
                      </div>
                      <div className="flex items-center gap-4">
                          <Mail className="h-5 w-5 text-muted-foreground" />
                           <div className="flex flex-col">
                            <span className="text-muted-foreground">Email</span>
                            <a href={`mailto:${selectedParent.email}`} className="text-primary hover:underline">{selectedParent.email}</a>
                          </div>
                      </div>
                      <div className="flex items-center gap-4">
                          <Phone className="h-5 w-5 text-muted-foreground" />
                           <div className="flex flex-col">
                            <span className="text-muted-foreground">Phone</span>
                            <a href={`tel:${selectedParent.phone}`} className="text-primary hover:underline">{selectedParent.phone}</a>
                          </div>
                      </div>
                      <div className="border-t pt-4 mt-2">
                         <span className="text-muted-foreground font-medium">Children</span>
                         <ul className="list-disc list-inside mt-2 space-y-1">
                            {selectedParent.children.map(child => (
                                <li key={child.id}>{child.name} - <span className="text-muted-foreground">{child.route}</span></li>
                            ))}
                         </ul>
                      </div>
                  </div>
              )}
              <DialogFooter>
                  <Button onClick={() => setIsDetailsOpen(false)}>Close</Button>
              </DialogFooter>
          </DialogContent>
      </Dialog>
    </div>
  );
}
