
import { getStudents, type Student } from './students';

export interface ParentWithChildren {
    name: string;
    email: string;
    phone: string;
    children: Student[];
}

export const getParents = async (): Promise<ParentWithChildren[]> => {
    const students = await getStudents();
    
    const parentsMap: Map<string, ParentWithChildren> = new Map();

    for (const student of students) {
        const parentEmail = student.parent.email;

        if (parentsMap.has(parentEmail)) {
            // Add child to existing parent entry
            const existingParent = parentsMap.get(parentEmail)!;
            existingParent.children.push(student);
        } else {
            // Create a new parent entry
            parentsMap.set(parentEmail, {
                ...student.parent,
                children: [student]
            });
        }
    }

    return Array.from(parentsMap.values());
};
